final:
module RefModule(
   input                clk,
   input                rst_n,
   output reg [3:0]     Q  
);
    reg [3:0] obf_binary_counter;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) obf_binary_counter <= 4'd0;
        else obf_binary_counter <= obf_binary_counter + 1;
    end

    always@* begin
        Q = obf_binary_counter ^ (obf_binary_counter >> 1);
    end
endmodule
